class Solution {
    public String resultingString(String s) {
        StringBuilder sb = new StringBuilder(s);
        boolean changed;
        do {
            changed = false;
            int n = sb.length();
            for (int i = 0; i < n - 1; i++) {
                char a = sb.charAt(i);
                char b = sb.charAt(i + 1);
                int diff = Math.abs(a - b);
                if (diff == 1 || diff == 25) {
                    sb.delete(i, i + 2);
                    changed = true;
                    break;
                }
            }
        } while (changed);
        return sb.toString();
    }
}
```
